private static String removeBOM(String str) {
    if (str.startsWith("\uFEFF")) { // UTF-8 BOM
        return str.substring(1);
    } else if (str.startsWith("\uFFFE\u0000") || str.startsWith("\u0000\uFFFE")) { // UTF-16 BOM
        return str.substring(2);
    } else if (str.startsWith("\uFEFF\u0000\u0000\u0000") || str.startsWith("\u0000\u0000\uFEFF\u0000")) { // UTF-32 BOM
        return str.substring(4);
    }
    return str;
}

