private static String stripBom(String docData, String charsetName) {
    if (charsetName.equalsIgnoreCase("UTF-8") && docData.startsWith("\uFEFF")) {
        return docData.substring(1);
    } else if (charsetName.equalsIgnoreCase("UTF-16BE") && docData.startsWith("\uFEFF")) {
        return docData.substring(1);
    } else if (charsetName.equalsIgnoreCase("UTF-16LE") && docData.startsWith("\uFFFE")) {
        return docData.substring(1);
    } else if (charsetName.equalsIgnoreCase("UTF-32BE") && docData.startsWith("\u0000\uFEFF")) {
        return docData.substring(2);
    } else if (charsetName.equalsIgnoreCase("UTF-32LE") && docData.startsWith("\uFFFE\u0000")) {
        return docData.substring(2);
    }
    return docData;
}
